            detail: 'This toast stays until you manually close it.',
            sticky: true,
            closable: true,
          }),
        showNonClosable: (): void =>
          toastService.add({
            severity: 'info',
            summary: 'Non-Closable',
            detail: 'No close button — auto-dismisses after 5 seconds.',
            closable: false,
            life: 5000,
          }),
        showShortLife: (): void =>
          toastService.add({
